// // This module decrements a 4-bit binary counter on each positive clock edge, with a reset functionality. When the reset input is active, the counter is set to zero, and the underflow flag is cleared. The counter will underflow to zero after reaching its minimum value of 0 (binary 0000), setting the underflow signal to indicate that an underflow has occurred on this transition.
module top_module(clk, reset, count, overflow);input clk, reset;
  output reg [3:0] count;
  output reg overflow;

  always @(posedge clk) begin
    if (reset) begin
      count <= 4'b0000;
      overflow <= 1'b0;
    end
    else if (count == 4'b1111) begin
      count <= 4'b0000;
      overflow <= 1'b1;
    end
    else begin
      count <= count + 1;
      overflow <= 1'b0;
    end
  end
endmodule
